import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.D2Ob5GRY.js";const _=JSON.parse('{"title":"维护费续费","description":"","frontmatter":{},"headers":[],"relativePath":"account/renewal.md","filePath":"account/renewal.md"}'),l={name:"account/renewal.md"};function n(i,a,c,h,s,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="维护费续费" tabindex="-1">维护费续费 <a class="header-anchor" href="#维护费续费" aria-label="Permalink to &quot;维护费续费&quot;">​</a></h1><blockquote><p>什么是年维护费、如何续费、续费后多久生效。</p></blockquote><h2 id="什么是年维护费" tabindex="-1">什么是年维护费 <a class="header-anchor" href="#什么是年维护费" aria-label="Permalink to &quot;什么是年维护费&quot;">​</a></h2><p>买断后须每年支付年维护费才能维持软件使用权；未支付则维护期到期后无法继续使用。系统中用「有效期至」表示当前维护期。</p><h2 id="如何续费-支付宝-微信支付" tabindex="-1">如何续费（支付宝 / 微信支付） <a class="header-anchor" href="#如何续费-支付宝-微信支付" aria-label="Permalink to &quot;如何续费（支付宝 / 微信支付）&quot;">​</a></h2><p>（占位：根据实际支付渠道填写，如门户「用户中心」→「续费」或联系管理员线下办理。）</p><h2 id="续费后多久生效" tabindex="-1">续费后多久生效 <a class="header-anchor" href="#续费后多久生效" aria-label="Permalink to &quot;续费后多久生效&quot;">​</a></h2><p>管理员在后台办理续费并延长「维护截止日」后，通常立即生效；若为授权码路径，主产品下次启动或心跳后会获取到新的有效期。</p><h2 id="续费后系统自动恢复说明" tabindex="-1">续费后系统自动恢复说明 <a class="header-anchor" href="#续费后系统自动恢复说明" aria-label="Permalink to &quot;续费后系统自动恢复说明&quot;">​</a></h2><ul><li>账号路径：维护截止日延长后，再次获取 token 即可正常使用。</li><li>授权码路径：validate/heartbeat 返回的 expires_at 更新后，主产品可继续使用。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/account/machine-management.html">机器管理</a></li><li><a href="/docs/account/account-status.html">账号状态说明</a></li></ul>',12)])])}const m=e(l,[["render",n]]);export{_ as __pageData,m as default};
